import React, { useState } from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css"; // Import styles

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false); // State to track if the menu is open

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <Link to="home" smooth={true} duration={500}>
          <img src="./images/logo.png" alt="Logo" />
        </Link>
      </div>
      
      <div className={`navbar-menu ${isOpen ? 'active' : ''}`}>
        <ul className="navbar-links">
          {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
            <li key={section}>
              <Link 
                to={section} 
                smooth={true} 
                duration={500} 
                activeClass="active" 
              >
                {section.replace(/^\w/, (c) => c.toUpperCase()).replace("-", " ")}
              </Link>
            </li>
          ))}
        </ul>
      </div>

      <div className="hamburger" onClick={toggleMenu}>
        <div className="bar"></div>
        <div className="bar"></div>
        <div className="bar"></div>
      </div>
    </nav>
  );
};

export default Navbar;
